int max(int a, int b) { return a > b ? a : b; }
int rodCutting(int price[], int n) {
    int dp[n + 1];
    dp[0] = 0;
    for (int i = 1; i <= n; i++) {
        int max_val = -1;
        for (int j = 1; j <= i; j++) {
            max_val = max(max_val, price[j - 1] + dp[i - j]);
        }
        dp[i] = max_val;
    }
    return dp[n];
}
