class Solution {
    // Main function to compute max rod cut value
    rodCutting(price, n) {
        // Initialize 2D dp array filled with -1
        const dp = Array.from({ length: n }, () => Array(n + 1).fill(-1));

        // Call recursive helper
        return this.helper(n - 1, n, price, dp);
    }

    // Recursive helper with memoization
    helper(i, length, price, dp) {
        // Base case: only rod length 1 available
        if (i === 0) {
            return length * price[0];
        }

        // Return precomputed value
        if (dp[i][length] !== -1) return dp[i][length];

        // Option 1: do not take
        let notTake = this.helper(i - 1, length, price, dp);

        // Option 2: take if fits
        let take = -Infinity;
        let rodLength = i + 1;
        if (rodLength <= length) {
            take = price[i] + this.helper(i, length - rodLength, price, dp);
        }

        // Store and return max
        dp[i][length] = Math.max(take, notTake);
        return dp[i][length];
    }
}

